import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.server.Route
import scala.xml.{XML, Node, NodeSeq, Elem}
import scala.util.{Try, Success, Failure}
import spray.json._
import akka.http.scaladsl.marshallers.sprayjson.SprayJsonSupport._
import javax.xml.parsers.SAXParserFactory

case class ConfigSetting(key: String, value: String, section: String)
case class ParsedConfig(settings: List[ConfigSetting], sections: List[String], errors: List[String])
case class ConfigRequest(xml: String)
case class ConfigResponse(success: Boolean, settings: List[ConfigSetting], sections: List[String], errors: List[String])

object JsonProtocol extends DefaultJsonProtocol {
  implicit val configSettingFormat: RootJsonFormat[ConfigSetting] = jsonFormat3(ConfigSetting)
  implicit val configRequestFormat: RootJsonFormat[ConfigRequest] = jsonFormat1(ConfigRequest)
  implicit val configResponseFormat: RootJsonFormat[ConfigResponse] = jsonFormat4(ConfigResponse)
}

object XmlConfigParser {

  private def createSecureSAXParser(): javax.xml.parsers.SAXParser = {
    val factory = SAXParserFactory.newInstance()
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    factory.setNamespaceAware(false)
    factory.newSAXParser()
  }

  def parseConfig(xmlString: String): ParsedConfig = {
    val errors = scala.collection.mutable.ListBuffer[String]()
    val settings = scala.collection.mutable.ListBuffer[ConfigSetting]()
    val sections = scala.collection.mutable.ListBuffer[String]()

    Try {
      val parser = createSecureSAXParser()
      XML.withSAXParser(parser).loadString(xmlString)
    } match {
      case Success(rootNode) =>
        extractSettings(rootNode, "", settings, sections, errors)
      case Failure(ex) =>
        errors += s"Failed to parse XML: ${ex.getMessage}"
    }

    ParsedConfig(settings.toList, sections.distinct.toList, errors.toList)
  }

  private def extractSettings(
    node: Node,
    parentPath: String,
    settings: scala.collection.mutable.ListBuffer[ConfigSetting],
    sections: scala.collection.mutable.ListBuffer[String],
    errors: scala.collection.mutable.ListBuffer[String]
  ): Unit = {
    node.label match {
      case "#PCDATA" => // skip text nodes at top level
      case _ =>
        val currentPath = if (parentPath.isEmpty) node.label else s"$parentPath.${node.label}"

        // Extract attributes as settings
        node.attributes.foreach { attr =>
          val key = s"$currentPath.@${attr.key}"
          settings += ConfigSetting(key, attr.value.text, currentPath)
        }

        val childElements = node.child.filter(_.label != "#PCDATA")

        if (childElements.isEmpty) {
          // Leaf node - extract text content as a setting
          val textContent = node.text.trim
          if (textContent.nonEmpty) {
            settings += ConfigSetting(currentPath, textContent, parentPath)
          }
        } else {
          // Section node
          sections += currentPath
          childElements.foreach { child =>
            extractSettings(child, currentPath, settings, sections, errors)
          }
        }
    }
  }

  def extractSettingByKey(xmlString: String, key: String): Option[String] = {
    val config = parseConfig(xmlString)
    config.settings.find(_.key == key).map(_.value)
  }

  def extractSection(xmlString: String, sectionPath: String): List[ConfigSetting] = {
    val config = parseConfig(xmlString)
    config.settings.filter(_.section.startsWith(sectionPath))
  }

  def resolveEntityReferences(xmlString: String, entities: Map[String, String]): String = {
    entities.foldLeft(xmlString) { case (xml, (entityName, entityValue)) =>
      xml.replace(s"&$entityName;", entityValue)
    }
  }
}

object ConfigManagementService extends App {

  import JsonProtocol._

  implicit val system: ActorSystem = ActorSystem("config-management")
  import system.dispatcher

  val route: Route = pathPrefix("api" / "config") {
    concat(
      path("parse") {
        post {
          entity(as[ConfigRequest]) { request =>
            val parsed = XmlConfigParser.parseConfig(request.xml)
            val response = ConfigResponse(
              success = parsed.errors.isEmpty,
              settings = parsed.settings,
              sections = parsed.sections,
              errors = parsed.errors
            )
            complete(response)
          }
        }
      },
      path("parse-with-entities") {
        post {
          entity(as[JsValue]) { json =>
            val fields = json.asJsObject.fields
            val xmlString = fields("xml").convertTo[String]
            val entities = fields.get("entities") match {
              case Some(JsObject(ents)) => ents.map { case (k, v) => k -> v.convertTo[String] }
              case _ => Map.empty[String, String]
            }
            val resolvedXml = XmlConfigParser.resolveEntityReferences(xmlString, entities)
            val parsed = XmlConfigParser.parseConfig(resolvedXml)
            val response = ConfigResponse(
              success = parsed.errors.isEmpty,
              settings = parsed.settings,
              sections = parsed.sections,
              errors = parsed.errors
            )
            complete(response)
          }
        }
      },
      path("setting" / Remaining) { key =>
        post {
          entity(as[ConfigRequest]) { request =>
            XmlConfigParser.extractSettingByKey(request.xml, key) match {
              case Some(value) =>
                complete(JsObject("key" -> JsString(key), "value" -> JsString(value)))
              case None =>
                complete(StatusCodes.NotFound, JsObject("error" -> JsString(s"Setting '$key' not found")))
            }
          }
        }
      },
      path("section" / Remaining) { sectionPath =>
        post {
          entity(as[ConfigRequest]) { request =>
            val sectionSettings = XmlConfigParser.extractSection(request.xml, sectionPath)
            complete(sectionSettings.toJson)
          }
        }
      },
      path("validate") {
        post {
          entity(as[ConfigRequest]) { request =>
            val parsed = XmlConfigParser.parseConfig(request.xml)
            val isValid = parsed.errors.isEmpty && parsed.settings.nonEmpty
            complete(JsObject(
              "valid" -> JsBoolean(isValid),
              "settingsCount" -> JsNumber(parsed.settings.size),
              "sectionsCount" -> JsNumber(parsed.sections.size),
              "errors" -> parsed.errors.toJson
            ))
          }
        }
      }
    )
  }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(route)

  bindingFuture.onComplete {
    case Success(binding) =>
      val address = binding.localAddress
      println(s"Configuration Management Service running at http://${address.getHostString}:${address.getPort}/")
    case Failure(ex) =>
      println(s"Failed to bind HTTP server: ${ex.getMessage}")
      system.terminate()
  }
}